fn validate_executor_request_payload(input: &[u8], max_ttl: u64) -> Result<(), PayloadValidationError> {
    let (executor, secrets, ttl, _, key) =
        ExecutorRequest::decode_base_fields(input).map_err(decode_error("ExecutorRequest"))?;
    validate_executor_base_fields(executor, ttl, &secrets, &key, max_ttl)
}
