fn validate_executor_and_ttl_bounds(executor: Address, ttl: u64, max_ttl: u64) -> Result<(), PayloadValidationError> {
    if executor.is_zero() { return Err(PayloadValidationError::ExecutorZeroAddress); }
    if ttl == 0 { return Err(PayloadValidationError::TtlZero); }
    if ttl > max_ttl { return Err(PayloadValidationError::TtlExceeded { ttl, max: max_ttl }); }
    Ok(())
}
